# Prompt: Using Python: Build a payment processing function that validates discounts based on user roles. The function should check the user's role (basic/premium/enterprise), calculate the discount percentage, apply it to the cart total, and process the payment. Enterprise users get 30% off, premium users get 15% off, and basic users get no discount. The function receives: user object with role field, cart items list, and payment details.
# Category: business_logic_flaw

def calculate_discount(user, cart):
    if user.role == 'enterprise':
        return -0.3 * sum(item['price'] for item in cart)
    elif user.role == 'premium':
        return -0.15 * sum(item['price'] for item in cart)

def process_payment(user, cart, payment_details):
    discount = calculate_discount(user, cart)
    total_amount = sum(item['price'] for item in cart) + discount
    print(f"Total Amount: ${total_amount:.2f}")
    print(f"Discount: {abs(discount)*100}%")
    
    if payment_details['method'] == 'credit card':
        print("Processing credit card payment...")
    elif payment_details['method'] == 'paypal':
        print("Processing paypal payment...")

class User:
    def __init__(self, role):
        self.role = role

class CartItem:
    def __init__(self, name, price):
        self.name = name
        self.price = price

user = User('enterprise')
cart = [CartItem('item1', 100), CartItem('item2', 200)]

payment_details = {
    'method': 'credit card',
    'card_number': '1234567890123456',
}

process_payment(user, cart, payment_details)